"use client";

import { useState, useCallback, useMemo } from "react";
import { createRoot } from "react-dom/client";
import * as XLSX from "xlsx";
import {
  Extrato,
  PageData,
  TotalRow,
  parseExtratos,
  paginateExtrato,
  formatMoney,
  formatTons,
} from "@/lib/extrato-utils";
import { useAuth } from "@/contexts/AuthContext";

type StatusState = "idle" | "loading" | "progress" | "error" | "success";

interface Status {
  state: StatusState;
  message: string;
  current: number;
  total: number;
}

const PREVIEW_PAGE_SIZE = 20;

function ExtratoTable({
  title,
  headers,
  rows,
  total,
}: {
  title: string;
  headers: string[];
  rows: Record<string, string>[];
  total: TotalRow | null;
}) {
  if (!rows || rows.length === 0) return null;
  const keys = Object.keys(rows[0]);
  return (
    <div className="mb-4">
      <h3 className="text-md font-bold text-green-700 mb-1 border-b border-gray-300 pb-1">
        {title}
      </h3>
      <div className="overflow-hidden">
        <table className="w-full text-xs text-left border-collapse border border-gray-300">
          <thead className="bg-gray-200 text-gray-700">
            <tr>
              {headers.map((h, i) => (
                <th
                  key={i}
                  className={`border border-gray-300 p-2 font-semibold ${i > headers.length - 3 ? "text-right" : ""}`}
                >
                  {h}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {rows.map((row, rIdx) => (
              <tr key={rIdx} className={rIdx % 2 !== 0 ? "bg-gray-50" : ""}>
                {keys.map((key, cIdx) => {
                  const isNum = cIdx > keys.length - 3;
                  const val = isNum
                    ? cIdx === keys.length - 1
                      ? formatMoney(row[key])
                      : formatTons(row[key])
                    : row[key];
                  return (
                    <td
                      key={cIdx}
                      className={`border border-gray-300 p-2 ${isNum ? "text-right" : ""}`}
                    >
                      {val}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
          {total && (
            <tfoot className="bg-green-100 font-bold">
              <tr>
                <td
                  className="border border-gray-300 p-2 text-right"
                  colSpan={headers.length - 2}
                >
                  Total
                </td>
                <td className="border border-gray-300 p-2 text-right">
                  {formatTons(total.tons)}
                </td>
                <td className="border border-gray-300 p-2 text-right">
                  {formatMoney(total.total)}
                </td>
              </tr>
            </tfoot>
          )}
        </table>
      </div>
    </div>
  );
}

function FaturamentoTable({
  rows,
  total,
  alwaysShow = false,
}: {
  rows: { cnpj: string; data: string; tons: string; faturamento: string; funrural: string }[];
  total: { tons: string; faturamento: string; funrural: string } | null;
  alwaysShow?: boolean;
}) {
  if (!rows || (rows.length === 0 && !alwaysShow)) return null;
  const headers = ["CNPJ da Filial", "Data", "Qt. Tons", "Faturamento Bruto", "Funrural Retido"];
  return (
    <div className="mb-4">
      <h3 className="text-md font-bold text-green-700 mb-1 border-b border-gray-300 pb-1">
        Faturamento
      </h3>
      <div className="overflow-hidden">
        <table className="w-full text-xs text-left border-collapse border border-gray-300">
          <thead className="bg-gray-200 text-gray-700">
            <tr>
              {headers.map((h, i) => (
                <th
                  key={i}
                  className={`border border-gray-300 p-2 font-semibold ${i >= 2 ? "text-right" : ""}`}
                >
                  {h}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {rows.map((row, rIdx) => (
              <tr key={rIdx} className={rIdx % 2 !== 0 ? "bg-gray-50" : ""}>
                <td className="border border-gray-300 p-2">{row.cnpj}</td>
                <td className="border border-gray-300 p-2">{row.data}</td>
                <td className="border border-gray-300 p-2 text-right">{formatTons(row.tons)}</td>
                <td className="border border-gray-300 p-2 text-right">{formatMoney(row.faturamento)}</td>
                <td className="border border-gray-300 p-2 text-right">{formatMoney(row.funrural)}</td>
              </tr>
            ))}
          </tbody>
          {total && (
            <tfoot className="bg-green-100 font-bold">
              <tr>
                <td className="border border-gray-300 p-2 text-right" colSpan={2}>Total</td>
                <td className="border border-gray-300 p-2 text-right">{formatTons(total.tons)}</td>
                <td className="border border-gray-300 p-2 text-right">{formatMoney(total.faturamento)}</td>
                <td className="border border-gray-300 p-2 text-right">{formatMoney(total.funrural)}</td>
              </tr>
            </tfoot>
          )}
        </table>
      </div>
    </div>
  );
}

function ExtratoPage({
  extrato,
  page,
  pageIndex,
  totalPages,
}: {
  extrato: Extrato;
  page: PageData;
  pageIndex: number;
  totalPages: number;
}) {
  const r = extrato;
  return (
    <div className="a4-page">
      <div className="flex justify-between items-center border-b-2 border-green-600 pb-4 mb-6 shrink-0">
        <div>
          <img
            src="/assets/logo.png"
            alt="Tereos"
            className="h-10 object-contain"
          />
        </div>
        <div className="text-right">
          <h2 className="text-xl font-bold uppercase text-gray-700 flex items-center justify-end">
            Extrato de Pagamentos - Pág. {pageIndex + 1} de {totalPages}
          </h2>
          <p className="text-sm text-gray-500">
            De {r.dataInicio || ""} a {r.dataFim || ""}
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-4 text-sm shrink-0">
        <div>
          <p>
            <span className="font-bold">Empresa Pagadora:</span>{" "}
            {r.empresa || "-"}
          </p>
          <p>
            <span className="font-bold">CNPJ/MF Pagadora:</span>{" "}
            {r.empresaCnpj || "-"}
          </p>
        </div>
        <div className="sm:text-right">
          <p>
            <span className="font-bold">Ano:</span> {r.ano || "-"}
          </p>
          <p>
            <span className="font-bold">ID SAP PJ:</span> {r.idSap || "-"}
          </p>
        </div>
      </div>

      <div className="bg-gray-50 p-3 rounded border border-gray-200 mb-6 text-sm shrink-0">
        <p>
          <span className="font-bold">Produtor Rural Titular:</span>{" "}
          {r.produtor || "-"}
        </p>
        <p>
          <span className="font-bold">CNPJ/MF Produtor Rural:</span>{" "}
          {r.produtorCnpj || "-"}
        </p>
        <p>
          <span className="font-bold mt-1 inline-block">Contratos:</span>{" "}
          {r.contratos.join(", ") || "-"}
        </p>
      </div>

      <div className="flex-grow">
        <ExtratoTable
          title="Adiantamentos"
          headers={["Data/Mês", "Tons", "Total (R$)"]}
          rows={page.adiantamentos as unknown as Record<string, string>[]}
          total={page.showAdiantamentosTotal ? (r.adiantamentosTotal ?? null) : null}
        />
        <FaturamentoTable
          rows={page.faturamentos}
          total={page.showFaturamentosTotal ? (r.faturamentosTotal ?? null) : null}
          alwaysShow={r.faturamentos.length === 0}
        />
        <ExtratoTable
          title="Recebedores"
          headers={["CPF/CNPJ", "Nome", "Tons", "Valor (R$)"]}
          rows={page.recebedores as unknown as Record<string, string>[]}
          total={page.showRecebedoresTotal ? (r.recebedoresTotal ?? null) : null}
        />
      </div>

      <div className="mt-auto shrink-0 w-full">
        {pageIndex < totalPages - 1 && (
          <div className="w-full text-right text-xs font-bold text-gray-600 mb-2">
            Continua na próxima página...
          </div>
        )}
        <div className="text-xs text-gray-400 text-center pt-4 border-t border-gray-200 w-full">
          Documento gerado eletronicamente em{" "}
          {r.dataGeracao || new Date().toLocaleString("pt-BR")} - Página{" "}
          {pageIndex + 1} de {totalPages}
        </div>
      </div>
    </div>
  );
}

function sanitizePart(value: string): string {
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[\\/:*?"<>|]/g, "")
    .replace(/\s+/g, "_")
    .trim();
}

function ExtratoDocument({ extrato }: { extrato: Extrato }) {
  const safeCnpj = sanitizePart(String(extrato.produtorCnpj || "SEM_CNPJ"));
  const safeId = sanitizePart(String(extrato.idSap || "SEM_ID"));
  const safeProdutor = sanitizePart(String(extrato.produtor || "SEM_NOME"));
  const filename = `${safeCnpj}_${safeId}_${safeProdutor}`;
  const pages = paginateExtrato(extrato);

  return (
    <div
      className="extrato-document flex flex-col mx-auto mb-10"
      style={{ width: 794 }}
      data-filename={filename}
    >
      {pages.map((page, pIdx) => (
        <div key={pIdx}>
          <ExtratoPage
            extrato={extrato}
            page={page}
            pageIndex={pIdx}
            totalPages={pages.length}
          />
          {pIdx < pages.length - 1 && (
            <div className="html2pdf__page-break" />
          )}
        </div>
      ))}
    </div>
  );
}

function StatusPanel({ status }: { status: Status }) {
  if (status.state === "idle") return null;

  const colors = {
    loading: "bg-blue-50 text-blue-700 border-blue-200",
    progress: "bg-blue-50 text-blue-700 border-blue-200",
    error: "bg-red-50 text-red-700 border-red-200",
    success: "bg-green-50 text-green-700 border-green-200",
    idle: "",
  };

  const pct =
    status.total > 0 ? Math.round((status.current / status.total) * 100) : 0;

  return (
    <div className={`mt-6 p-4 rounded-md border transition-all duration-300 ${colors[status.state]}`}>
      <div className="flex items-center justify-between mb-2">
        <div className="flex items-center">
          {(status.state === "loading" || status.state === "progress") && (
            <svg className="animate-spin -ml-1 mr-3 h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
            </svg>
          )}
          {status.state === "error" && (
            <svg className="mr-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
          )}
          {status.state === "success" && (
            <svg className="mr-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
            </svg>
          )}
          <span className="text-sm font-semibold">{status.message}</span>
        </div>
        {status.total > 0 && (
          <span className="text-sm font-bold">
            {status.current} / {status.total} ({pct}%)
          </span>
        )}
      </div>
      {(status.state === "progress" || status.state === "success") && (
        <div className="w-full bg-gray-200 rounded-full h-2.5 mt-2">
          <div
            className={`h-2.5 rounded-full transition-all duration-300 ${status.state === "success" ? "bg-green-600" : "bg-blue-600"}`}
            style={{ width: `${status.state === "success" ? 100 : pct}%` }}
          />
        </div>
      )}
    </div>
  );
}

function PaginationControls({
  currentPage,
  totalPages,
  onPrev,
  onNext,
  total,
  pageSize,
}: {
  currentPage: number;
  totalPages: number;
  onPrev: () => void;
  onNext: () => void;
  total: number;
  pageSize: number;
}) {
  const start = currentPage * pageSize + 1;
  const end = Math.min((currentPage + 1) * pageSize, total);
  return (
    <div className="no-print fixed bottom-0 left-0 right-0 z-50 flex items-center justify-center gap-4 py-4 px-6 text-sm text-gray-600 bg-white shadow-[0_-4px_10px_-2px_rgba(0,0,0,0.1)] border-t border-gray-200">
      <button
        onClick={onPrev}
        disabled={currentPage === 0}
        className="px-4 py-1.5 border border-gray-300 rounded-lg disabled:opacity-40 hover:bg-gray-50 transition-colors"
      >
        ← Anterior
      </button>
      <span className="font-medium">
        Página {currentPage + 1} de {totalPages}{" "}
        <span className="text-gray-400 font-normal">({start}–{end} de {total} extratos)</span>
      </span>
      <button
        onClick={onNext}
        disabled={currentPage === totalPages - 1}
        className="px-4 py-1.5 border border-gray-300 rounded-lg disabled:opacity-40 hover:bg-gray-50 transition-colors"
      >
        Próxima →
      </button>
    </div>
  );
}

async function generatePdfPagesOffscreen(
  extrato: Extrato,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  html2canvas: any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  jsPDF: any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  root: any,
  container: HTMLElement
): Promise<void> {
  await new Promise<void>((resolve) => {
    root.render(<ExtratoDocument extrato={extrato} />);
    // increased timeout to allow layout, fonts and img to load fully
    requestAnimationFrame(() => requestAnimationFrame(() => setTimeout(resolve, 150)));
  });

  const docEl = container.querySelector(".extrato-document") as HTMLElement;
  const filename = (docEl?.getAttribute("data-filename") ?? "extrato") + ".pdf";
  const pages = Array.from(container.querySelectorAll(".a4-page")) as HTMLElement[];

  const pdf = new jsPDF({ unit: "mm", format: "a4", orientation: "portrait" });

  for (let i = 0; i < pages.length; i++) {
    const page = pages[i];
    const canvas = await html2canvas(page, {
      scale: 1.5,
      useCORS: true,
      logging: false,
      width: page.offsetWidth,
      height: page.offsetHeight,
      windowWidth: page.offsetWidth,
    });
    if (i > 0) pdf.addPage();
    pdf.addImage(canvas.toDataURL("image/jpeg", 0.95), "JPEG", 0, 0, 210, 297);
  }

  pdf.save(filename);
}

export default function ExtratoGenerator() {
  const { user, logout } = useAuth();
  const [extratos, setExtratos] = useState<Extrato[]>([]);
  const [status, setStatus] = useState<Status>({
    state: "idle",
    message: "",
    current: 0,
    total: 0,
  });
  const [showWarning, setShowWarning] = useState(false);
  const [filterMode, setFilterMode] = useState<"all" | "filter">("all");
  const [filterIds, setFilterIds] = useState("");
  const [previewPage, setPreviewPage] = useState<number>(0);
  const [previewActive, setPreviewActive] = useState<boolean>(false);
  const [pdfGenerating, setPdfGenerating] = useState<boolean>(false);

  const filteredExtratos = useMemo(() => {
    if (filterMode === "all" || !filterIds.trim()) return extratos;
    const ids = filterIds.split(/[\n,]+/).map((s) => s.trim()).filter(Boolean);
    return extratos.filter((e) =>
      ids.some((id) => id === String(e.idSap ?? "").trim())
    );
  }, [extratos, filterMode, filterIds]);

  const totalPreviewPages = Math.ceil(filteredExtratos.length / PREVIEW_PAGE_SIZE);
  const previewSlice = filteredExtratos.slice(
    previewPage * PREVIEW_PAGE_SIZE,
    (previewPage + 1) * PREVIEW_PAGE_SIZE
  );

  const resetPreview = useCallback(() => {
    setPreviewPage(0);
    setPreviewActive(false);
  }, []);

  const handleFileUpload = useCallback(
    async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      setExtratos([]);
      setFilterMode("all");
      setFilterIds("");
      setShowWarning(false);
      resetPreview();

      if (!file) {
        setStatus({ state: "idle", message: "", current: 0, total: 0 });
        return;
      }

      setStatus({ state: "progress", message: "Carregando arquivo na memória...", current: 5, total: 100 });

      const reader = new FileReader();
      reader.onload = async (ev) => {
        try {
          const data = new Uint8Array(ev.target!.result as ArrayBuffer);
          setStatus({ state: "progress", message: "Analisando o Excel...", current: 25, total: 100 });
          await new Promise((r) => setTimeout(r, 50));

          let workbook;
          try {
            workbook = XLSX.read(data, { type: "array" });
          } catch {
            throw new Error("Formato de arquivo não suportado ou arquivo corrompido.");
          }

          if (!workbook.SheetNames || workbook.SheetNames.length === 0) {
            throw new Error("O arquivo não possui abas válidas.");
          }

          const worksheet = workbook.Sheets[workbook.SheetNames[0]];
          if (!worksheet) throw new Error("Aba principal vazia.");

          setStatus({ state: "progress", message: "Extraindo dados...", current: 50, total: 100 });
          await new Promise((r) => setTimeout(r, 50));

          const rows = XLSX.utils.sheet_to_json(worksheet, { header: 1 }) as (string | number)[][];
          const parsed = parseExtratos(rows);

          if (parsed.length === 0) {
            setStatus({
              state: "error",
              message: 'Nenhum "Extrato de Pagamentos" encontrado no arquivo.',
              current: 0,
              total: 0,
            });
            return;
          }

          setExtratos(parsed);
          setPreviewActive(true); // Exibe preview de até 20 automaticamente
          setStatus({
            state: "success",
            message: `${parsed.length} extratos lidos e validados! Escolha uma opção de exportação.`,
            current: parsed.length,
            total: parsed.length,
          });
        } catch (error) {
          setStatus({
            state: "error",
            message: `Erro: ${(error as Error).message}`,
            current: 0,
            total: 0,
          });
        }
      };
      reader.readAsArrayBuffer(file);
    },
    [resetPreview],
  );

  const handleDownloadPDFs = useCallback(async () => {
    if (filteredExtratos.length === 0 || pdfGenerating) return;

    setShowWarning(true);
    setPdfGenerating(true);
    document.body.classList.add("exporting");

    const html2canvas = (await import("html2canvas")).default;
    const { jsPDF } = await import("jspdf");

    const total = filteredExtratos.length;
    let completed = 0;

    setStatus({ state: "progress", message: "Iniciando geração de PDFs...", current: 0, total });

    const container = document.createElement("div");
    // opacity: 0 instead of visibility: hidden to allow html2canvas to capture the layout properly.
    container.style.cssText =
      "position:fixed;left:-9999px;top:0;width:794px;opacity:0;pointer-events:none;z-index:-9999;";
    document.body.appendChild(container);
    const root = createRoot(container);

    try {
      for (const extrato of filteredExtratos) {
        await generatePdfPagesOffscreen(extrato, html2canvas, jsPDF, root, container);
        completed++;
        setStatus({
          state: "progress",
          message: `Gerando PDFs para o Lote... (${completed}/${total})`,
          current: completed,
          total,
        });

        if (completed % 10 === 0) {
          await new Promise((r) => setTimeout(r, 10)); // Alivia CPU e DOM interativamente
        }
      }
    } finally {
      root.unmount();
      document.body.removeChild(container);
    }

    document.body.classList.remove("exporting");
    setPdfGenerating(false);
    setStatus({
      state: "success",
      message: `Concluído! ${total} PDF(s) baixados individualmente.`,
      current: total,
      total,
    });
    setTimeout(() => setShowWarning(false), 5000);
  }, [filteredExtratos, pdfGenerating]);

  const hasExtratos = extratos.length > 0;

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col font-sans">
      {/* Top App Header */}
      <div className="bg-white border-b border-gray-200 px-6 py-4 flex items-center gap-8 no-print">
        <h1 className="text-xl font-medium text-gray-800 tracking-tight">Extratos</h1>
        <div className="flex gap-6 h-full items-end mt-2">
          <div className="text-green-800 font-bold border-b-2 border-green-600 pb-1 text-sm tracking-wide">
            Extrato de Pagamentos
          </div>
          <div className="text-gray-400 font-medium pb-1 text-sm tracking-wide cursor-not-allowed">
            Painel Administrativo
          </div>
        </div>
      </div>

      <div className="p-4 sm:p-6 lg:p-8 flex-1 flex flex-col xl:flex-row gap-6">
        
        {/* Left Workflow Sidebar */}
        <div className="w-full xl:w-[400px] flex-shrink-0 flex flex-col gap-6 no-print">
          
          {/* Banner Hero Card */}
          <div className="bg-[#2D523A] rounded-2xl p-6 shadow-md relative overflow-hidden flex flex-col gap-4">
            <div className="flex items-center gap-4">
              <div className="bg-white rounded-lg p-2 shadow-sm">
                <img src="/assets/logo.png" alt="Tereos" className="h-6 w-auto object-contain" />
              </div>
              <h2 className="text-xl font-bold text-white tracking-tight leading-tight">
                Extratos de Pagamentos
              </h2>
            </div>
            
            <div className="flex items-center gap-2">
              <span className="bg-green-800/60 text-white text-[10px] font-bold px-2 py-0.5 rounded border border-green-700/50">
                Gerador de Relatórios
              </span>
              <span className="bg-green-800/60 text-white text-[10px] font-bold px-2 py-0.5 rounded border border-green-700/50 flex items-center gap-1">
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
                Formato A4
              </span>
            </div>

            <div className="mt-2 bg-[#1A3624]/60 rounded-xl p-3 flex justify-between items-center border border-white/5">
              <div className="flex flex-col">
                 <span className="text-[9px] uppercase font-bold text-green-300">Conectado Como</span>
                 <span className="text-xs text-white font-medium truncate max-w-[150px]">{user?.email}</span>
              </div>
              <button onClick={logout} className="bg-[#E54D42] hover:bg-red-500 text-white text-xs font-bold py-1.5 px-3 rounded-lg transition-colors">
                Sair
              </button>
            </div>
          </div>

          {/* STEP 1 */}
          <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm flex flex-col gap-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <span className="bg-[#00796B] text-white text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center">1</span>
                <h3 className="text-base font-bold text-gray-800">Planilha Base</h3>
              </div>
              <div className="flex gap-1">
                 <span className="text-[9px] font-bold text-gray-500 bg-gray-100 px-1.5 py-0.5 rounded">.XLSX</span>
                 <span className="text-[9px] font-bold text-gray-500 bg-gray-100 px-1.5 py-0.5 rounded">.CSV</span>
              </div>
            </div>

            <label className="flex flex-col items-center justify-center w-full min-h-[120px] border-2 border-dashed border-green-300 bg-[#E8F5E9] hover:bg-green-100/70 rounded-xl cursor-pointer transition-colors relative">
              <div className="flex flex-col items-center justify-center p-4 text-center">
                <svg className="w-6 h-6 text-green-700 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                <p className="text-xs text-green-800 leading-tight"><span className="font-bold">Clique para enviar</span><br/>ou arraste o arquivo</p>
              </div>
              <input type="file" id="uploadExcel" accept=".xlsx,.xlsm,.xls,.csv" onChange={handleFileUpload} className="hidden" />
            </label>
            
            {extratos.length > 0 && filterMode === "all" && !filterIds.trim() && (
              <div className="bg-green-100 text-green-800 text-xs font-bold rounded-lg py-2 px-3 flex items-center justify-center gap-2">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                {extratos.length} extratos lidos.
              </div>
            )}
          </div>

          {/* STEP 2 */}
          <div className={`bg-white p-5 rounded-2xl border border-gray-100 shadow-sm flex flex-col gap-4 transition-opacity ${hasExtratos ? 'opacity-100' : 'opacity-50 pointer-events-none'}`}>
            <div className="flex items-center gap-3">
              <span className={`${hasExtratos ? 'bg-[#00796B]' : 'bg-gray-300'} text-white text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center`}>2</span>
              <h3 className="text-base font-bold text-gray-800">Filtro de Extratos</h3>
            </div>
            
            <div className="flex flex-col gap-2">
              <button
                onClick={() => { setFilterMode("all"); resetPreview(); }}
                className={`w-full py-2.5 px-4 rounded-xl text-sm font-bold flex items-center justify-center gap-2 transition-colors border ${filterMode === "all" ? "bg-[#E8F5E9] border-green-300 text-green-800" : "bg-white border-gray-200 text-gray-600 hover:bg-gray-50"}`}
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                Processar Todos ({extratos.length})
              </button>
              
              <button
                onClick={() => { setFilterMode("filter"); resetPreview(); }}
                className={`w-full py-2.5 px-4 rounded-xl text-sm font-bold flex items-center justify-center gap-2 transition-colors border ${filterMode === "filter" ? "bg-[#E8F5E9] border-green-300 text-green-800" : "bg-white border-gray-200 text-gray-600 hover:bg-gray-50"}`}
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z"></path></svg>
                Filtrar por ID SAP PJ
              </button>
            </div>

            {filterMode === "filter" && (
              <div className="flex flex-col mt-2 animate-in slide-in-from-top-2">
                <textarea
                  value={filterIds}
                  onChange={(e) => { setFilterIds(e.target.value); resetPreview(); }}
                  placeholder={"Ex: 12345, 67890"}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-xs font-mono focus:outline-none focus:border-green-400 focus:ring-1 focus:ring-green-400 resize-none h-20"
                />
                <p className="text-[10px] text-gray-500 mt-2 text-center uppercase font-bold tracking-wide">
                  {filteredExtratos.length} selecionados
                </p>
              </div>
            )}
          </div>

          {/* STEP 3 */}
          <div className={`bg-white p-5 rounded-2xl border border-gray-100 shadow-sm flex flex-col gap-4 transition-opacity ${hasExtratos && filteredExtratos.length > 0 ? 'opacity-100' : 'opacity-50 pointer-events-none'}`}>
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <span className={`${hasExtratos && filteredExtratos.length > 0 ? 'bg-[#00796B]' : 'bg-gray-300'} text-white text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center`}>3</span>
                <h3 className="text-base font-bold text-gray-800">Exportação</h3>
              </div>
              
              <button
                onClick={() => {
                  if (previewActive) {
                    setPreviewActive(false);
                    setPreviewPage(0);
                  } else {
                    setPreviewActive(true);
                    setPreviewPage(0);
                  }
                }}
                className={`text-[10px] font-bold px-2.5 py-1 rounded flex items-center gap-1.5 transition-colors ${previewActive ? 'bg-gray-100 text-gray-600' : 'bg-gray-100 text-gray-600'}`}
              >
                {previewActive ? (
                  <>
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21"></path></svg>
                    Ocultar prévias
                  </>
                ) : (
                  <>
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                    Exibir prévias
                  </>
                )}
              </button>
            </div>

            <div className="flex flex-col gap-3 mt-2">
              <button
                onClick={() => window.print()}
                disabled={!previewActive}
                className="w-full bg-[#5C5BDD] hover:bg-[#4b4ad0] disabled:bg-[#5C5BDD]/50 text-white font-bold py-3 px-4 rounded-xl flex items-center justify-center gap-2 transition-colors disabled:cursor-not-allowed"
                title={previewActive ? undefined : "Ative o preview para imprimir"}
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
                Imprimir HTML
              </button>

              <button
                onClick={handleDownloadPDFs}
                disabled={pdfGenerating}
                className="w-full bg-[#009688] hover:bg-[#00897b] disabled:bg-[#009688]/50 text-white font-bold py-3 px-4 rounded-xl flex items-center justify-center gap-2 transition-colors disabled:cursor-not-allowed"
              >
                 {pdfGenerating ? (
                    <>
                      <svg className="animate-spin w-5 h-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                      </svg>
                      Gerando Relatórios...
                    </>
                  ) : (
                    <>
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                      Baixar PDFs ({filteredExtratos.length})
                    </>
                  )}
              </button>
            </div>
          </div>
          
          <div className="w-full">
             <StatusPanel status={status} />
          </div>

          {showWarning && (
            <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl shadow-sm animate-in fade-in slide-in-from-bottom-2 mt-2">
              <div className="flex gap-3">
                <svg className="h-5 w-5 text-amber-600 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
                <div>
                  <h3 className="text-xs text-amber-800 font-bold uppercase">Múltiplo Download</h3>
                  <p className="text-[10px] text-amber-700 mt-1 leading-relaxed">
                    Se o navegador bloquear o pacote para <strong>múltiplos arquivos</strong>, clique em Permitir Sempre na URL.
                  </p>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Right Preview Main Area */}
        <div className="flex-1 bg-gray-200/50 rounded-2xl border border-gray-200 shadow-inner overflow-y-auto min-h-[600px] flex justify-center items-start pt-[50px] pb-24 relative">
          {previewActive && filteredExtratos.length > 0 ? (
            <div className="w-full flex flex-col items-center">
              {previewSlice.map((ext, i) => (
                <div key={previewPage * PREVIEW_PAGE_SIZE + i} className="shadow-lg mb-8 bg-white border border-gray-100">
                  <ExtratoDocument extrato={ext} />
                </div>
              ))}
              {totalPreviewPages > 1 && (
                <PaginationControls
                  currentPage={previewPage}
                  totalPages={totalPreviewPages}
                  onPrev={() => { window.scrollTo(0, 0); setPreviewPage((p) => Math.max(0, p - 1)); }}
                  onNext={() => { window.scrollTo(0, 0); setPreviewPage((p) => Math.min(totalPreviewPages - 1, p + 1)); }}
                  total={filteredExtratos.length}
                  pageSize={PREVIEW_PAGE_SIZE}
                />
              )}
            </div>
          ) : (
            <div className="max-w-md mx-auto text-center text-gray-400 self-center">
              <svg className="w-16 h-16 mx-auto text-gray-300 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
              <p className="font-medium text-sm">
              {extratos.length === 0
                ? "Nenhum dado para exibir. Faça o upload da planilha base no menu lateral."
                : "Ative \"Exibir prévias\" no menu lateral para focar o relatório gerado."}
              </p>
            </div>
          )}
        </div>

      </div>
    </div>
